-- 2차 배치: 단계별 how-to / 트러블슈팅 / 구체 스펙 (상세 보강). 줄바꿈은 E-string \n 사용.

INSERT INTO faqs (category, question, answer, sort_order, created_at, updated_at) VALUES
-- 시작하기 (상세)
('시작하기', '처음 1시간, 무엇을 하면 가장 좋나요?', E'추천 순서입니다.\n1) 설정 → Threads 연결에서 계정을 연결합니다(예약·자동 발행·통계에 필요).\n2) AI 생성에서 주제 1개로 5개 카드를 만들어 관심도 점수가 높은 것을 저장합니다.\n3) 라이브러리에서 그 글을 열어 미리보기로 확인하고, 추천 시간대에 맞춰 예약합니다.\n4) (선택) 분석 → ROI에서 추적 링크를 만들어 글에 넣으면 클릭·매출까지 측정됩니다.\n대시보드의 "시작하기" 카드가 1~3단계를 자동으로 체크해 줍니다.', 15, now(), now()),
('시작하기', '키 없이도 둘러볼 수 있나요?', E'네. 로그인 화면의 "개발용 로그인"(로컬 환경) 또는 데모 데이터로 대부분의 화면을 둘러볼 수 있습니다. 다만 실제 AI 생성(Anthropic 키)과 실제 발행(Threads 키)은 키가 설정되어야 동작합니다. 관심도 점수·훅 분석·추천 시간대 등은 키 없이도 작동합니다.', 16, now(), now()),
('시작하기', '데이터는 안전하게 보관되나요?', E'콘텐츠·연결 정보는 서버 DB에 저장되며, Threads 토큰 등 민감 값은 환경변수/암호화된 연결로 다룹니다. 로그인은 Google OAuth라 비밀번호를 저장하지 않습니다. 개인정보 처리방침은 로그인·계정 화면 하단 링크에서 확인하세요.', 17, now(), now()),

-- AI 콘텐츠 생성 (상세)
('AI 콘텐츠 생성', '좋은 주제를 입력하는 요령이 있나요?', E'구체적일수록 결과가 좋습니다.\n- 나쁜 예: "마케팅"\n- 좋은 예: "1인 창업가가 자주 하는 콘텐츠 실수 3가지"\n대상 독자, 상황, 숫자(3가지/7일 등)를 넣으면 훅이 강해집니다. 주제 입력칸 아래의 추천 칩(스타트업·생산성 등)을 눌러 빠르게 시작할 수도 있어요.', 27, now(), now()),
('AI 콘텐츠 생성', '관심도 점수는 어떻게 올리나요?', E'점수는 6개 요소로 계산됩니다.\n- 훅(첫 문장) 35점: 궁금증·충격·이득을 첫 줄에.\n- 길이 20점: 너무 짧거나 길지 않게.\n- 질문 12점: 독자에게 묻는 문장 포함.\n- CTA 13점: 행동 유도(댓글·저장·링크).\n- 해시태그 10점: 2~5개 적정.\n- 구조 10점: 줄바꿈·가독성.\n상세 모달의 "분석/개선 팁"이 부족한 항목을 콕 집어줍니다.', 28, now(), now()),
('AI 콘텐츠 생성', '생성 결과가 마음에 안 들어요.', E'1) 톤·목표를 바꿔 다시 생성해 보세요(같은 주제도 결과가 크게 달라집니다).\n2) "훅 비교"로 첫 문장만 여러 개 받아 가장 강한 것으로 교체하세요.\n3) 저장 후 상세 모달에서 직접 편집할 수 있습니다(관심도 점수가 실시간 갱신).\n4) 개수를 늘려(최대 10) 후보를 많이 받아 고르세요.', 29, now(), now()),
('AI 콘텐츠 생성', '생성한 글이 사라졌어요/안 보여요.', E'생성 카드는 저장해야 라이브러리에 남습니다. 저장하지 않고 화면을 벗어나면 사라져요. 라이브러리에서 안 보이면 상단 검색어·상태 필터·관심도 필터가 걸려 있는지 확인하고 초기화해 보세요.', 30, now(), now()),

-- 라이브러리 (상세)
('라이브러리', '상태(초안/예약/발행/실패)는 각각 무엇인가요?', E'- 초안: 저장만 된 상태(언제든 편집·예약·발행 가능)\n- 예약: 지정 시각에 자동 발행 대기\n- 발행: Threads에 올라간 상태\n- 실패: 발행 시도 중 오류(예: 토큰 만료) — 알림으로 안내되며 재연결 후 다시 시도하세요.\n- 재연결 필요: 계정 토큰 문제로 발행 보류 상태.', 44, now(), now()),
('라이브러리', '정렬·필터는 어떻게 쓰나요?', E'상단에서 최신순/관심도 높은순·낮은순 정렬, 상태별(초안/예약/발행) 필터, 관심도 구간(80+/60+/60미만) 필터를 조합할 수 있습니다. 검색창(본문·해시태그·CTA)과도 함께 동작해, 예를 들어 "관심도 낮은 초안만" 모아 개선할 수 있어요.', 45, now(), now()),
('라이브러리', '이미지는 어떻게 첨부하나요?', E'글 상세 모달에서 이미지를 업로드하면 첨부됩니다. 발행 시 Threads 게시물에 함께 올라가고, 미리보기에서 어떻게 보일지 확인할 수 있어요. 첨부 이미지는 모달에서 제거할 수도 있습니다.', 46, now(), now()),

-- 예약·스케줄 (상세)
('예약·스케줄', '예약한 글은 정확히 언제 나가나요?', E'지정한 시각이 되면 백엔드 스케줄러가 자동으로 발행합니다(수십 초 단위로 확인). 발행에는 Threads 연결이 유효해야 하며, 토큰이 만료/재연결 필요 상태면 보류되고 알림으로 안내됩니다.', 53, now(), now()),
('예약·스케줄', '과거 시각으로 예약하면 어떻게 되나요?', E'권장하지 않습니다. 과거나 너무 임박한 시각은 의도대로 동작하지 않을 수 있어요. 미래 시각으로 지정하고, 추천 시간대(스케줄 상단)를 참고하세요.', 54, now(), now()),
('예약·스케줄', '예약을 수정/취소하려면?', E'라이브러리 또는 스케줄에서 해당 글을 열어 발행 시각을 바꾸거나 초안으로 되돌릴 수 있습니다. 캘린더/목록 보기를 토글해 한눈에 관리하세요.', 55, now(), now()),

-- Threads 연결 (상세/트러블슈팅)
('Threads 연결', '연결 팝업이 안 뜨거나 막혀요.', E'1) 브라우저 팝업 차단을 해제하세요(팝업이 막히면 전체 페이지 이동으로 대체됩니다).\n2) 서버에 Threads 앱 키가 설정되어 있어야 합니다(미설정 시 진행되지 않음).\n3) 로그인된 Threads 세션이 연결하려는 계정인지 확인하세요.', 66, now(), now()),
('Threads 연결', 'OAuth에서 "안전하지 않은 로그인" 오류가 나요.', E'Meta는 HTTPS 리디렉션만 허용합니다. 로컬/개발에서는 https 터널(예: cloudflared)로 https 콜백 URL을 사용해야 하고, Threads 앱 설정의 Redirect Callback URL에 정확히 등록해야 합니다. 운영 배포 시 고정 https 도메인을 쓰면 해결됩니다.', 67, now(), now()),
('Threads 연결', '"테스트 초대를 수락하지 않았습니다" 오류가 나요.', E'앱이 개발 모드일 때 발생합니다. Meta 앱 설정에서 해당 Threads 계정을 테스터로 추가하고, 그 계정으로 초대를 수락해야 연결됩니다. 정식 공개(앱 검수 통과) 후에는 일반 사용자도 연결할 수 있습니다.', 68, now(), now()),
('Threads 연결', '팔로워/조회 통계가 0이거나 안 보여요.', E'팔로워 수는 인사이트 권한(threads_manage_insights)이 있어야 표시됩니다. 조회·좋아요 등은 최근 30일 기준이며, 계정/기간에 따라 값이 없으면 —로 표시됩니다. 팔로잉 수는 Threads API가 제공하지 않아 표시하지 않습니다.', 69, now(), now()),

-- 댓글 자동화 (상세)
('댓글 자동화', '자동 답글은 얼마나 자주 확인하나요?', E'백엔드 스케줄러가 주기적으로 활성 규칙의 대상 게시물 댓글을 확인해 매칭되면 답글을 보냅니다. 같은 댓글에 중복 답글이 가지 않도록 이미 응답한 댓글은 기록해 건너뜁니다.', 73, now(), now()),
('댓글 자동화', '특정 게시물에만 자동 답글을 달 수 있나요?', E'규칙의 "대상 게시물"을 특정 글로 지정하면 그 글에만, "전체"로 두면 발행된 모든 글에 적용됩니다. 다중 계정인 경우 각 게시물이 발행된 계정의 토큰으로 답글이 나갑니다.', 74, now(), now()),
('댓글 자동화', '자동 답글이 안 나가요.', E'점검 항목: 1) 규칙이 활성(켜짐) 상태인지, 2) 대상 게시물이 실제로 발행되어 Threads에 있는지, 3) 키워드가 댓글과 매칭되는지("테스트"로 확인), 4) Threads 연결이 유효한지(토큰 만료 시 보류).', 75, now(), now()),

-- 추적링크·ROI (상세/스펙)
('추적링크·ROI', '클릭 수는 어떻게 집계되나요?', E'추적 링크(/r/코드)를 통한 방문만 셉니다. 동일 방문자(IP 해시 기준)의 30분 내 중복 클릭은 1회로 처리하고, 봇으로 판단되는 User-Agent는 제외해 과대 집계를 막습니다.', 86, now(), now()),
('추적링크·ROI', '전환 웹훅 요청 형식을 정확히 알려주세요.', E'POST {엔드포인트}\n헤더:\n- Content-Type: application/json\n- X-PostFlow-Timestamp: 현재 epoch초\n- X-PostFlow-Signature: HMAC_SHA256(시크릿, "타임스탬프.본문")의 hex\n본문 예: {"slug":"추적링크코드","amount":29000,"currency":"KRW","note":"강의"}\nslug 대신 postId도 가능합니다. 타임스탬프가 5분 이상 차이 나면 거부됩니다(재전송 방지). 계정 화면의 "연동 가이드"에 복사용 코드가 있습니다.', 87, now(), now()),
('추적링크·ROI', '전환 웹훅이 401(거부)로 와요.', E'대부분 서명 문제입니다. 1) 서명 대상이 "타임스탬프.본문"인지(본문만 서명하면 실패), 2) 본문 문자열이 전송 본문과 100% 동일한지(공백·키 순서 포함), 3) 타임스탬프가 현재 시각(epoch초)이고 5분 이내인지, 4) 시크릿이 최신인지(재발급했다면 갱신) 확인하세요.', 88, now(), now()),
('추적링크·ROI', 'ROI가 마이너스로 나와요.', E'비용이 매출보다 크면 ROI는 음수가 됩니다. 비용 입력값이 정확한지, 전환(매출)이 웹훅으로 잘 들어왔는지 분석 → 수익 탭에서 확인하세요. 매출이 0이면 추적 링크/전환 웹훅 연동이 안 된 상태일 수 있습니다.', 89, now(), now()),

-- 플랜·결제 (상세)
('플랜·결제', '플랜별 한도를 표로 알려주세요.', E'- Free: 월 30회 생성, 예약·시리즈·다중계정 불가\n- Starter: 월 300회 생성, 예약 발행 가능\n- Pro: 무제한 생성, 시리즈·분석 포함\n- Business: 무제한 + 다중 계정 + 우선 지원\n현재 사용량과 잠금 상태는 계정 화면에서 확인할 수 있습니다.', 95, now(), now()),
('플랜·결제', '다운그레이드(하위 플랜 전환)는 어떻게 되나요?', E'구독을 취소하면 결제한 기간 말까지 현재 플랜을 그대로 쓰고, 기간 종료 시 무료로 전환됩니다. 즉시 낮은 유료 플랜으로 바꾸는 것은 결제사 관리 페이지(구독 관리)에서 처리됩니다.', 96, now(), now()),
('플랜·결제', '한도를 초과하면 어떻게 되나요?', E'해당 작업(생성·예약·시리즈·다중계정)이 막히고 안내 메시지와 함께 업그레이드 버튼이 표시됩니다. 생성 한도는 매월 1일(KST) 기준으로 초기화됩니다. 업그레이드하면 즉시 한도가 풀립니다.', 97, now(), now()),
('플랜·결제', '결제 정보는 어디에 저장되나요?', E'카드 정보는 PostFlow가 직접 보관하지 않고 결제사(Stripe)가 안전하게 처리합니다. PostFlow는 구독 상태와 결제사 고객 식별자만 보관합니다. 영수증·카드 변경은 구독 관리(결제사 포털)에서 가능합니다.', 98, now(), now()),

-- 기타 (상세)
('기타', '내보낸 CSV에는 어떤 항목이 들어가나요?', E'게시물의 id, 본문, 해시태그, CTA, 상태, 관심도 점수, 예약시각, 발행시각, 생성시각이 포함됩니다. 엑셀에서 바로 열 수 있도록 UTF-8(BOM) CSV로 저장되며, JSON 내보내기는 전체 필드를 그대로 백업합니다.', 105, now(), now()),
('기타', '추적 링크를 댓글이나 글에 어떻게 넣나요?', E'분석 → ROI에서 링크를 만들면 /r/코드 형태의 단축 URL이 생깁니다. 이 URL을 글 본문이나 댓글, 댓글 자동화 템플릿의 {link} 자리에 넣으면 클릭이 측정되고 전환과 연결됩니다.', 106, now(), now()),
('기타', '실제 서비스로 운영하려면 무엇이 필요한가요?', E'1) AI 키(Anthropic) — 실제 생성, 2) Threads 앱 키 + 고정 https 도메인 + 앱 검수 — 실제 발행, 3) 결제 키(Stripe) — 실결제, 4) 배포(서버/도메인). 키만 넣으면 기존 기능이 그대로 실동작하도록 설계되어 있습니다.', 107, now(), now()),
('기타', '버그를 발견했거나 기능 제안이 있어요.', E'deerkrg@gmail.com 으로 화면 캡처와 함께 보내주시면 빠르게 확인하겠습니다. 자주 묻는 질문은 계속 업데이트됩니다.', 108, now(), now());
